const name = $input.first().json['Full Name'] || '';
const email = $input.first().json['Email Address'] || '';
const lastPeriodRaw = $input.first().json['Last Period Start Date'] || '';
const cycleLength = parseInt($input.first().json['Cycle Length (days)']) || 28;

const lastPeriod = new Date(lastPeriodRaw);

// Core cycle calculations
const nextPeriod = new Date(lastPeriod);
nextPeriod.setDate(nextPeriod.getDate() + cycleLength);

const ovulationDate = new Date(nextPeriod);
ovulationDate.setDate(ovulationDate.getDate() - 14);

const fertileStart = new Date(ovulationDate);
fertileStart.setDate(fertileStart.getDate() - 5);

const fertileEnd = new Date(ovulationDate);
fertileEnd.setDate(fertileEnd.getDate() + 1);

const pmsStart = new Date(nextPeriod);
pmsStart.setDate(pmsStart.getDate() - 5);

// Format dates as YYYY-MM-DD
const fmt = d => d.toISOString().split('T')[0];

return [{
  json: {
    name,
    email,
    last_period_date: fmt(lastPeriod),
    cycle_length: cycleLength,
    subscribed_date: fmt(new Date()),
    next_period: fmt(nextPeriod),
    ovulation_date: fmt(ovulationDate),
    fertile_start: fmt(fertileStart),
    fertile_end: fmt(fertileEnd),
    pms_start: fmt(pmsStart),
    last_email_sent: '',
    active: 'true'
  }
}];

const data = $input.first().json;

const emailTemplates = {
  period_incoming: {
    subject: `🔴 Heads Up ${data.name} — Your Period is Coming in 3 Days`,
    heading: '🔴 Period Incoming',
    color1: '#c0392b',
    color2: '#e74c3c',
    intro: `Your period is expected to start in 3 days on <strong>${data.nextPeriodStr}</strong>. Now is a great time to prepare.`,
    tips: [
      '🛍️ Stock up on pads, tampons, or your preferred products',
      '💊 If you experience cramps, consider having pain relief on hand',
      '🍫 Reduce caffeine and salty foods to minimize bloating',
      '🧘 Light stretching or yoga can help ease incoming discomfort',
      '😴 Prioritize sleep over the next few nights'
    ],
    closing: 'Listen to your body over the next few days. Rest when you need to. 💜'
  },
  period_start: {
    subject: `🩸 Your Period Has Started — Self-Care Tips for ${data.name}`,
    heading: '🩸 Your Period Has Started',
    color1: '#922b21',
    color2: '#c0392b',
    intro: `Your period is here. Be gentle with yourself today and over the coming days.`,
    tips: [
      '🌡️ A hot water bottle on your lower abdomen can ease cramps',
      '💧 Stay hydrated — aim for at least 8 glasses of water today',
      '🥗 Iron-rich foods like spinach and lentils help replenish what you lose',
      '🚶 Light walks can improve circulation and reduce pain',
      '📵 It is okay to say no to things today — rest is productive'
    ],
    closing: 'You handle this every month. You are stronger than you think. 🌸'
  },
  ovulation: {
    subject: `🥚 Ovulation Window Alert for ${data.name}`,
    heading: '🥚 You Are in Your Ovulation Window',
    color1: '#1a7a4a',
    color2: '#27ae60',
    intro: `Today is your ovulation day. Your fertile window runs from <strong>${data.fertileStartStr}</strong> to <strong>${data.fertileEndStr}</strong>.`,
    tips: [
      '⚡ Energy levels are often highest during ovulation — use this time well',
      '💪 This is a great phase for high intensity workouts',
      '🗣️ Many women feel more confident and social during ovulation',
      '🧠 Cognitive sharpness tends to peak — great time for presentations or decisions',
      '💤 Some women experience mild ovulation pain — this is normal'
    ],
    closing: 'Your body is working exactly as it should. Stay in tune with it. 💚'
  },
  pms_prep: {
    subject: `😮‍💨 PMS Window Starting Soon — Tips for ${data.name}`,
    heading: '😮‍💨 PMS Window is Starting',
    color1: '#6c3483',
    color2: '#8e44ad',
    intro: `Your PMS window starts today and runs until your period on <strong>${data.nextPeriodStr}</strong>. A little preparation goes a long way.`,
    tips: [
      '🧘 Reduce stress with meditation, journaling, or gentle movement',
      '🍬 Cravings are normal — satisfy them mindfully without guilt',
      '📵 Set boundaries this week — protect your energy',
      '😴 Sleep at least 7-8 hours to help regulate mood',
      '💬 Let someone close to you know you might need extra support'
    ],
    closing: 'PMS is real and valid. Take care of yourself without apology. 💜'
  }
};

const template = emailTemplates[data.emailType];
const tipsList = template.tips.map(t => `<li style="margin-bottom: 10px;">${t}</li>`).join('');

const htmlEmail = `<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #fff0f7; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 30px auto; background: #ffffff; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.08); }
    .header { background: linear-gradient(135deg, ${template.color1}, ${template.color2}); padding: 30px; text-align: center; color: white; }
    .header h1 { margin: 0; font-size: 22px; }
    .body { padding: 30px; color: #333; }
    .tip-box { background: #fff0f7; border-left: 4px solid ${template.color1}; padding: 16px 20px; border-radius: 8px; margin: 20px 0; }
    .footer { background: #fff0f7; padding: 16px; text-align: center; font-size: 12px; color: #999; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>${template.heading}</h1>
    </div>
    <div class="body">
      <p>Hi ${data.name} 👋</p>
      <p>${template.intro}</p>
      <div class="tip-box">
        <strong>💡 Tips for Today:</strong>
        <ul style="padding-left: 20px; margin-top: 12px;">
          ${tipsList}
        </ul>
      </div>
      <p>${template.closing}</p>
      <p style="font-size: 13px; color: #888;">📅 Cycle Day ${data.cycleDay} &nbsp;|&nbsp; Phase: ${data.phase}</p>
    </div>
    <div class="footer">You subscribed to Cycle Wellness reminders.<br/>Reply STOP to unsubscribe.</div>
  </div>
</body>
</html>`;

return [{
  json: {
    ...data,
    htmlEmail,
    subject: template.subject
  }
}];

const today = new Date();
today.setHours(0, 0, 0, 0);
const fmt = d => new Date(d).toISOString().split('T')[0];
const todayStr = fmt(today);

const results = [];

for (const item of $input.all()) {
  const u = item.json;

  const nextPeriod = new Date(u.next_period);
  const ovulationDate = new Date(u.ovulation_date);
  const fertileStart = new Date(u.fertile_start);
  const fertileEnd = new Date(u.fertile_end);
  const pmsStart = new Date(u.pms_start);
  const lastPeriod = new Date(u.last_period_date);

  // Set all to midnight for clean comparison
  [nextPeriod, ovulationDate, fertileStart, fertileEnd, pmsStart, lastPeriod].forEach(d => d.setHours(0,0,0,0));

  // Calculate cycle day
  const cycleDay = Math.floor((today - lastPeriod) / 86400000) + 1;

  // 3 days before period
  const threeDaysBefore = new Date(nextPeriod);
  threeDaysBefore.setDate(threeDaysBefore.getDate() - 3);
  threeDaysBefore.setHours(0,0,0,0);

  // Determine what to send today
  let emailType = null;

  if (fmt(today) === fmt(nextPeriod)) {
    emailType = 'period_start';
  } else if (fmt(today) === fmt(threeDaysBefore)) {
    emailType = 'period_incoming';
  } else if (fmt(today) === fmt(ovulationDate)) {
    emailType = 'ovulation';
  } else if (fmt(today) === fmt(pmsStart)) {
    emailType = 'pms_prep';
  }

  // Determine current phase label
  let phase = 'Follicular';
  if (today >= pmsStart && today < nextPeriod) phase = 'PMS';
  else if (today >= nextPeriod && cycleDay <= 5) phase = 'Menstrual';
  else if (today >= fertileStart && today <= fertileEnd) phase = 'Fertile';
  else if (fmt(today) === fmt(ovulationDate)) phase = 'Ovulation';

  // Skip if no email to send today
  if (!emailType) continue;

  // Skip if this email type already sent this cycle
  const lastSent = u.last_email_sent || '';
  if (lastSent.includes(`${emailType}_${u.next_period}`)) continue;

  results.push({
    json: {
      ...u,
      today: todayStr,
      cycleDay,
      phase,
      emailType,
      nextPeriodStr: fmt(nextPeriod),
      ovulationStr: fmt(ovulationDate),
      fertileStartStr: fmt(fertileStart),
      fertileEndStr: fmt(fertileEnd),
      pmsStartStr: fmt(pmsStart)
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];

const today = new Date();
today.setHours(0, 0, 0, 0);

return $input.all().map(item => {
  const u = item.json;

  const nextPeriod = new Date(u.next_period);
  const ovulationDate = new Date(u.ovulation_date);
  const fertileStart = new Date(u.fertile_start);
  const fertileEnd = new Date(u.fertile_end);
  const pmsStart = new Date(u.pms_start);
  const lastPeriod = new Date(u.last_period_date);

  [nextPeriod, ovulationDate, fertileStart, fertileEnd, pmsStart, lastPeriod].forEach(d => d.setHours(0,0,0,0));

  const cycleDay = Math.floor((today - lastPeriod) / 86400000) + 1;

  // Determine phase
  let phase = 'Follicular';
  if (today >= pmsStart && today < nextPeriod) phase = 'PMS';
  else if (cycleDay <= 5) phase = 'Menstrual';
  else if (today >= fertileStart && today <= fertileEnd) phase = 'Fertile';
  else if (today.toISOString().split('T')[0] === ovulationDate.toISOString().split('T')[0]) phase = 'Ovulation';

  const daysUntilPeriod = Math.ceil((nextPeriod - today) / 86400000);

  const prompt = `You are a warm and knowledgeable women's health and wellness coach. Generate a personalized weekly wellness digest for a woman currently in her ${phase} phase of her menstrual cycle.

User:
- Name: ${u.name}
- Current Phase: ${phase}
- Cycle Day: ${cycleDay}
- Days Until Next Period: ${daysUntilPeriod}
- Cycle Length: ${u.cycle_length} days

Respond ONLY in this JSON format:
{
  "phase_summary": "2-3 sentences explaining what happens in the body during this phase",
  "energy_tip": "One specific tip for managing energy this week",
  "nutrition_tip": "One specific nutrition recommendation for this phase",
  "movement_tip": "One specific exercise or movement recommendation",
  "mindset_tip": "One specific mental wellness tip for this phase",
  "weekly_affirmation": "A powerful affirmation for women in this phase",
  "what_to_expect": "One thing she should expect physically or emotionally this week"
}

Rules:
- Use her name throughout
- Be warm, sisterly, and empowering
- Give specific practical tips not generic advice
- Keep each tip to 1-2 sentences`;

  return {
    json: {
      ...u,
      phase,
      cycleDay,
      daysUntilPeriod,
      prompt
    }
  };
});

const response = items[0].json.output[0].content[0].text;
const cleaned = response.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

const userData = $('Calculate Phase & Build Prompt').item.json;

const phaseColors = {
  Menstrual: { color1: '#922b21', color2: '#c0392b', emoji: '🩸' },
  Follicular: { color1: '#1a5276', color2: '#2980b9', emoji: '🌱' },
  Fertile: { color1: '#1a7a4a', color2: '#27ae60', emoji: '💚' },
  Ovulation: { color1: '#1a7a4a', color2: '#27ae60', emoji: '🥚' },
  PMS: { color1: '#6c3483', color2: '#8e44ad', emoji: '😮‍💨' }
};

const colors = phaseColors[userData.phase] || phaseColors.Follicular;

const htmlEmail = `<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #fff0f7; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 30px auto; background: #ffffff; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.08); }
    .header { background: linear-gradient(135deg, ${colors.color1}, ${colors.color2}); padding: 30px; text-align: center; color: white; }
    .header h1 { margin: 0; font-size: 22px; }
    .badge { display: inline-block; background: rgba(255,255,255,0.25); padding: 4px 14px; border-radius: 20px; font-size: 13px; margin-top: 8px; }
    .body { padding: 30px; color: #333; }
    .tip-card { background: #fff0f7; border-left: 4px solid ${colors.color1}; padding: 14px 18px; border-radius: 8px; margin: 14px 0; }
    .tip-label { font-weight: bold; color: ${colors.color1}; font-size: 12px; text-transform: uppercase; margin-bottom: 6px; }
    .affirmation { background: linear-gradient(135deg, ${colors.color1}, ${colors.color2}); color: white; padding: 20px; border-radius: 8px; text-align: center; font-size: 16px; font-style: italic; margin: 20px 0; }
    .footer { background: #fff0f7; padding: 16px; text-align: center; font-size: 12px; color: #999; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>${colors.emoji} Weekly Wellness Digest</h1>
      <span class="badge">${userData.phase} Phase · Day ${userData.cycleDay} · ${userData.daysUntilPeriod} days until period</span>
    </div>
    <div class="body">
      <p>Hi ${userData.name} 👋</p>
      <p>${parsed.phase_summary}</p>

      <div class="tip-card">
        <div class="tip-label">⚡ Energy This Week</div>
        ${parsed.energy_tip}
      </div>
      <div class="tip-card">
        <div class="tip-label">🥗 Nutrition Tip</div>
        ${parsed.nutrition_tip}
      </div>
      <div class="tip-card">
        <div class="tip-label">🏃 Movement Tip</div>
        ${parsed.movement_tip}
      </div>
      <div class="tip-card">
        <div class="tip-label">🧠 Mindset Tip</div>
        ${parsed.mindset_tip}
      </div>
      <div class="tip-card">
        <div class="tip-label">📅 What to Expect This Week</div>
        ${parsed.what_to_expect}
      </div>

      <div class="affirmation">
        💜 ${parsed.weekly_affirmation}
      </div>
    </div>
    <div class="footer">You subscribed to Cycle Wellness reminders.<br/>Reply STOP to unsubscribe.</div>
  </div>
</body>
</html>`;

return [{
  json: {
    ...userData,
    htmlEmail,
    subject: `${colors.emoji} Your Weekly Wellness Digest — ${userData.phase} Phase · Day ${userData.cycleDay}`
  }
}];
